import React from 'react';
import {
  AbsoluteFill,
  interpolate,
  useCurrentFrame,
  Easing,
} from 'remotion';

const TITLE_FADE_IN_DURATION = 30;

interface CaptionProps {
  text: string;
  startFrame: number;
  endFrame: number;
}

const Caption: React.FC<CaptionProps> = ({ text, startFrame, endFrame }) => {
  const frame = useCurrentFrame();
  const POP_DURATION = 12;

  const opacity = interpolate(frame, [startFrame, startFrame + POP_DURATION, endFrame - 5, endFrame], [0, 1, 1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.cubic),
  });

  const scale = interpolate(frame, [startFrame, startFrame + POP_DURATION], [0.6, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.back(1.7)),
  });

  if (frame < startFrame || frame >= endFrame) return null;

  return (
    <div
      style={{
        position: 'absolute',
        bottom: 200,
        left: 0,
        right: 0,
        textAlign: 'center',
        opacity,
        transform: `scale(${scale})`,
      }}
    >
      <span
        style={{
          color: '#ffffff',
          fontSize: 96,
          fontFamily: 'sans-serif',
          fontWeight: 700,
          textShadow: '0 4px 16px rgba(0,0,0,0.5)',
        }}
      >
        {text}
      </span>
    </div>
  );
};

export const MyVideo: React.FC = () => {
  const frame = useCurrentFrame();

  const titleOpacity = interpolate(frame, [0, TITLE_FADE_IN_DURATION], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.quad),
  });

  return (
    <AbsoluteFill style={{ backgroundColor: '#1a1a2e' }}>
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          opacity: titleOpacity,
        }}
      >
        <h1
          style={{
            color: '#e0e0ff',
            fontSize: 160,
            fontFamily: 'sans-serif',
            fontWeight: 900,
            margin: 0,
            letterSpacing: '-0.02em',
          }}
        >
          Hello
        </h1>
      </div>

      <Caption text="one" startFrame={120} endFrame={180} />
      <Caption text="two" startFrame={180} endFrame={240} />
      <Caption text="three" startFrame={240} endFrame={300} />
    </AbsoluteFill>
  );
};

